import React, { useState, useEffect } from 'react';
import Logo from './Logo.png'; 

// BRAND COLORS
const gold = '#D4AF37'; 
const terracotta = '#C04000'; 
const softCream = '#FDF5E6'; 

function App() {
  const [activeCategory, setActiveCategory] = useState('Small Chops');
  const [currentSlide, setCurrentSlide] = useState(0);
  const [cart, setCart] = useState([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [showBankDetails, setShowBankDetails] = useState(false);
  const [isClockedIn, setIsClockedIn] = useState(false);

  const whatsappNumber = "2349122731172";
  const bankInfo = { 
    bank: "PREMIUMTRUST BANK", 
    account: "0112326977", 
    name: "OLUKOYA OMOTOYOSI" 
  };

  const slides = [
    { title: "SMALL CHOPS", subtitle: "Lagos' finest selection.", bgImage: "/images/chops_bg.jpg" },
    { title: "THE HAIR EDIT", subtitle: "Luxury units & blends.", bgImage: "/images/wigs_bg.jpg" },
    { title: "OFFICE LUNCH", subtitle: "Premium corporate dining.", bgImage: "/images/lunch_bg.jpg" }
  ];

  const menuData = {
    CHOPS: [
      { id: 1, name: "The Starter Pack", price: "15,000", desc: "7 Samosas, 7 Springrolls, 15 Puff-puff, 10 Mosa, 4 Grilled Chicken.", img: "/images/starter.jpg" },
      { id: 2, name: "The Signature Platter", price: "25,000", desc: "10 Samosas, 10 Springrolls, 25 Puff-puff, 20 Mosa, 8 Grilled Chicken.", img: "/images/signature.jpg" },
      { id: 3, name: "The Owambe Special", price: "150,000", desc: "Full event catering for 50 people.", img: "/images/owambe.jpg" },
      { id: 4, name: "The Customized Package", price: "200,000", desc: "Bespoke menu for 60 people and above.", img: "/images/custom.jpg", isCustom: true }
    ],
    LUNCH: [
      { day: "Monday", meal: "Smoky Jollof, Grilled Chicken & Salad" },
      { day: "Tuesday", meal: "Creamy Pasta, Sauteed Prawns & Garlic Bread" },
      { day: "Wednesday", meal: "Native Rice, Shredded Beef & Fried Plantain" },
      { day: "Thursday", meal: "Stir-fry Noodles, Teriyaki Wings & Veggies" },
      { day: "Friday", meal: "Chef's Special Surprise (TGIF Menu)" }
    ],
    WIGS: [
      { type: "Human Hair", items: [
          { id: 201, name: "Raw Cambodian", price: "85,000", desc: "14\" Frontal Unit", img: "/images/hair1.jpg" },
          { id: 202, name: "Bone Straight", price: "120,000", desc: "12\" Double Drawn", img: "/images/hair2.jpg" }
      ]},
      { type: "Premium Fibre", items: [
          { id: 203, name: "Sleek Straight", price: "35,000", desc: "Heat Resistant", img: "/images/hair3.jpg" },
          { id: 204, name: "Deep Wave", price: "38,000", desc: "Pre-styled", img: "/images/hair4.jpg" }
      ]}
    ]
  };

  useEffect(() => {
    const timer = setInterval(() => setCurrentSlide((s) => (s + 1) % slides.length), 5000);
    return () => clearInterval(timer);
  }, [slides.length]);

  const addToCart = (item) => setCart([...cart, item]);
  const removeFromCart = (index) => {
    const newCart = [...cart];
    newCart.splice(index, 1);
    setCart(newCart);
  };
  const total = cart.reduce((acc, item) => acc + parseInt(item.price.replace(/,/g, '')), 0);

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', color: '#fff', fontFamily: 'system-ui, sans-serif' }}>
      
      {/* 1. HEADER LOGO */}
      <header style={{ padding: '15px 20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', position: 'sticky', top: 0, backgroundColor: 'rgba(0,0,0,0.95)', zIndex: 1000 }}>
        <img src={Logo} alt="Logo" style={{ height: '55px' }} />
        <div style={{ fontSize: '1.4rem' }} onClick={() => setIsCartOpen(true)}>🛒 {cart.length}</div>
      </header>

      {/* 2. GALLERY STYLE SLIDER (NOT BACKGROUND) */}
      <div style={{ width: '100%', height: '320px', display: 'flex', alignItems: 'center', justifyContent: 'center', position: 'relative', overflow: 'hidden', padding: '10px 0' }}>
        {slides.map((slide, index) => (
          <div key={index} style={{ 
            position: 'absolute', 
            width: '90%', 
            height: '240px', 
            opacity: index === currentSlide ? 1 : 0, 
            transition: 'all 0.8s ease-in-out',
            borderRadius: '20px',
            backgroundColor: '#111', // Frame background
            overflow: 'hidden',
            boxShadow: '0 10px 30px rgba(0,0,0,0.8)',
            border: '1px solid #222'
          }}>
            {/* THIS IS THE KEY CHANGE: img tag instead of background-image */}
            <img 
              src={process.env.PUBLIC_URL + slide.bgImage} 
              alt={slide.title}
              style={{ 
                width: '100%', 
                height: '100%', 
                objectFit: 'contain', // Changed from cover to contain to prevent it filling like a background
                backgroundColor: '#1a1a1a' 
              }} 
            />
            
            {/* FLOATING TEXT CAPTION */}
            <div style={{ 
              position: 'absolute', 
              bottom: 0, 
              width: '100%', 
              padding: '15px 20px', 
              background: 'linear-gradient(transparent, rgba(0,0,0,0.9))',
              textAlign: 'left'
            }}>
              <h2 style={{ fontSize: '1.4rem', fontWeight: '900', margin: 0 }}>{slide.title}</h2>
              <p style={{ fontSize: '0.9rem', color: gold, margin: '3px 0 0' }}>{slide.subtitle}</p>
            </div>
          </div>
        ))}
      </div>

      {/* 3. NAV TABS */}
      <div style={{ display: 'flex', gap: '10px', overflowX: 'auto', padding: '20px 25px', scrollbarWidth: 'none' }}>
        {['Small Chops', 'Office Lunch', 'Wigs'].map((item) => (
          <button key={item} onClick={() => setActiveCategory(item)} style={{ whiteSpace: 'nowrap', padding: '12px 25px', borderRadius: '30px', border: 'none', backgroundColor: activeCategory === item ? terracotta : '#111', color: '#fff', fontWeight: '800' }}>
            {item}
          </button>
        ))}
      </div>

      {/* 4. PRODUCTS */}
      <main style={{ paddingBottom: '140px' }}>
        {activeCategory === 'Small Chops' && menuData.CHOPS.map((item) => (
          <div key={item.id} style={{ display: 'flex', backgroundColor: '#0A0A0A', borderRadius: '18px', margin: '0 25px 15px', padding: '15px', alignItems: 'center', border: '1px solid #1a1a1a' }}>
            <div style={{ width: '90px', height: '90px', borderRadius: '12px', overflow: 'hidden', flexShrink: 0 }}>
              <img src={item.img} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="" />
            </div>
            <div style={{ flex: 1, paddingLeft: '15px' }}>
              <h4 style={{ fontSize: '1.05rem', margin: 0 }}>{item.name}</h4>
              <div style={{ color: gold, fontWeight: 'bold', marginTop: '4px' }}>₦{item.price}</div>
            </div>
            {item.isCustom ? (
              <button onClick={() => window.open(`https://wa.me/${whatsappNumber}?text=Book ${item.name}`)} style={{ backgroundColor: gold, padding: '10px 18px', borderRadius: '20px', border: 'none', fontWeight: '900', fontSize: '0.8rem' }}>BOOK</button>
            ) : (
              <button onClick={() => addToCart(item)} style={{ backgroundColor: terracotta, padding: '10px 18px', borderRadius: '20px', border: 'none', color: '#fff', fontWeight: '900', fontSize: '0.8rem' }}>ADD</button>
            )}
          </div>
        ))}

        {activeCategory === 'Office Lunch' && (
          <div style={{ padding: '0 25px' }}>
            <div style={{ backgroundColor: '#111', padding: '30px', borderRadius: '20px', textAlign: 'center', marginBottom: '20px', border: `1px solid ${isClockedIn ? '#2ecc71' : terracotta}` }}>
              <button onClick={() => setIsClockedIn(true)} style={{ backgroundColor: isClockedIn ? '#2ecc71' : terracotta, color: '#fff', border: 'none', padding: '14px 30px', borderRadius: '15px', fontWeight: '900' }}>{isClockedIn ? "LOGGED IN" : "START DAILY ORDER"}</button>
            </div>
            {menuData.LUNCH.map((item) => (
              <div key={item.day} style={{ padding: '15px 0', borderBottom: '1px solid #1a1a1a', display: 'flex', justifyContent: 'space-between' }}>
                <span style={{ color: terracotta, fontWeight: '800' }}>{item.day}</span>
                <span style={{ textAlign: 'right', flex: 1, marginLeft: '20px', color: '#ccc' }}>{item.meal}</span>
              </div>
            ))}
          </div>
        )}

        {activeCategory === 'Wigs' && menuData.WIGS.map((cat) => (
          <div key={cat.type} style={{ padding: '0 25px', marginBottom: '25px' }}>
            <h3 style={{ fontSize: '0.85rem', color: terracotta, marginBottom: '15px' }}>{cat.type}</h3>
            {cat.items.map((item) => (
              <div key={item.id} style={{ display: 'flex', backgroundColor: '#0A0A0A', borderRadius: '18px', padding: '15px', alignItems: 'center', marginBottom: '12px' }}>
                <div style={{ width: '80px', height: '80px', borderRadius: '12px', overflow: 'hidden', flexShrink: 0 }}>
                  <img src={item.img} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="" />
                </div>
                <div style={{ flex: 1, paddingLeft: '15px' }}>
                  <h4 style={{ fontSize: '1rem' }}>{item.name}</h4>
                  <div style={{ color: gold, fontWeight: 'bold' }}>₦{item.price}</div>
                </div>
                <button onClick={() => addToCart(item)} style={{ backgroundColor: terracotta, padding: '10px 18px', borderRadius: '20px', border: 'none', color: '#fff', fontWeight: '900' }}>ADD</button>
              </div>
            ))}
          </div>
        ))}
      </main>

      {/* 5. FLOATING CART */}
      {cart.length > 0 && (
        <div onClick={() => setIsCartOpen(true)} style={{ position: 'fixed', bottom: '25px', left: '50%', transform: 'translateX(-50%)', width: '90%', backgroundColor: terracotta, padding: '18px', borderRadius: '25px', display: 'flex', justifyContent: 'space-between', zIndex: 1001 }}>
          <span style={{ fontWeight: '900' }}>{cart.length} ITEMS</span>
          <span style={{ fontWeight: '900' }}>VIEW BOX ₦{total.toLocaleString()}</span>
        </div>
      )}

      {/* 6. CART MODAL */}
      {isCartOpen && (
        <div style={{ position: 'fixed', bottom: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(0,0,0,0.98)', zIndex: 2000, display: 'flex', alignItems: 'flex-end' }}>
          <div style={{ width: '100%', backgroundColor: '#000', borderTopLeftRadius: '30px', borderTopRightRadius: '30px', padding: '35px 25px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
              <h3 style={{ color: gold }}>{showBankDetails ? "Payment" : "Your Selection"}</h3>
              <button onClick={() => {setIsCartOpen(false); setShowBankDetails(false);}} style={{ background: 'none', border: 'none', color: '#fff', fontSize: '1.8rem' }}>✕</button>
            </div>
            {!showBankDetails ? (
              <>
                {cart.map((item, i) => (
                  <div key={i} style={{ display: 'flex', justifyContent: 'space-between', padding: '12px 0', borderBottom: '1px solid #111' }}>
                    <span>{item.name}</span>
                    <span style={{ color: gold }}>₦{item.price}</span>
                  </div>
                ))}
                <div style={{ marginTop: '30px' }}>
                  <button onClick={() => setShowBankDetails(true)} style={{ width: '100%', padding: '18px', backgroundColor: gold, borderRadius: '15px', border: 'none', fontWeight: '900', marginBottom: '10px' }}>BANK TRANSFER</button>
                  <button onClick={() => window.open(`https://wa.me/${whatsappNumber}`)} style={{ width: '100%', padding: '18px', backgroundColor: '#25D366', borderRadius: '15px', border: 'none', color: '#fff', fontWeight: '900' }}>WHATSAPP ORDER</button>
                </div>
              </>
            ) : (
              <div style={{ textAlign: 'center' }}>
                <h2 style={{ color: gold }}>₦{total.toLocaleString()}</h2>
                <p><strong>{bankInfo.bank}</strong></p>
                <p>{bankInfo.account}</p>
                <p>{bankInfo.name}</p>
                <button onClick={() => setShowBankDetails(false)} style={{ marginTop: '20px', background: 'none', border: 'none', color: '#555' }}>Go back</button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
